import React from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';

function Services() {
  const services = [
    {
      icon: '🌐',
      titre: 'Réseau à distance',
      description: 'Configuration et administration des réseaux, mise en place de VPN, diagnostic de pannes et sécurisation des infrastructures.',
      details: ['Configuration VPN', 'Administration réseau', 'Diagnostic de pannes', 'Sécurisation infrastructure', 'Surveillance du trafic']
    },
    {
      icon: '💻',
      titre: 'Systèmes à distance',
      description: 'Configuration des systèmes, installation de logiciels, gestion des utilisateurs et diagnostic des pannes informatiques.',
      details: ['Administration Linux/Windows', 'Installation de logiciels', 'Gestion des utilisateurs', 'Active Directory', 'Diagnostic système']
    },
    {
      icon: '🔧',
      titre: 'Assistance sur site',
      description: 'Installation de réseaux WiFi, dépannage informatique et configuration de routeurs pour entreprises et particuliers à Dakar.',
      details: ['Installation WiFi', 'Dépannage informatique', 'Configuration routeurs', 'Câblage réseau', 'Support technique']
    },
    {
      icon: '🔒',
      titre: 'Cybersécurité',
      description: 'Audit de sécurité, test de vulnérabilités et mise en place de solutions de protection pour vos systèmes.',
      details: ['Audit de sécurité', 'Test de vulnérabilités', 'Protection des données', 'Analyse des risques', 'Recommandations']
    },
    {
      icon: '🌍',
      titre: 'Création de sites web',
      description: 'Mise en place de sites vitrines et portfolios avec WordPress, adaptés à vos besoins.',
      details: ['Sites vitrines', 'Portfolios', 'WordPress', 'Design responsive', 'Maintenance']
    },
    {
      icon: '📚',
      titre: 'Formation & Cours',
      description: 'Cours particuliers en informatique et réseaux pour étudiants et professionnels à Dakar.',
      details: ['Cours réseaux', 'Linux débutant', 'Cybersécurité', 'Support technique', 'À domicile ou en ligne']
    }
  ];

  return (
    <div style={{background: '#000000', minHeight: '100vh', paddingTop: '100px'}}>

      {/* HEADER */}
      <motion.section
        initial={{opacity: 0, y: -30}}
        animate={{opacity: 1, y: 0}}
        transition={{duration: 0.8}}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)',
          borderBottom: '2px solid #00aa00'
        }}
      >
        <h1 style={{fontSize: '48px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px'}}>
          Mes Services
        </h1>
        <p style={{color: '#aaaaaa', fontSize: '18px', maxWidth: '600px', margin: '0 auto'}}>
          Des prestations informatiques sérieuses et adaptées à vos besoins
        </p>
      </motion.section>

      {/* SERVICES GRID */}
      <section style={{padding: '80px 50px'}}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: '30px', maxWidth: '1200px', margin: '0 auto'
        }}>
          {services.map((service, index) => (
            <motion.div
              key={index}
              initial={{opacity: 0, y: 30}}
              whileInView={{opacity: 1, y: 0}}
              whileHover={{scale: 1.03, boxShadow: '0 0 30px rgba(0,170,0,0.4)'}}
              transition={{duration: 0.4, delay: index * 0.1}}
              style={{
                background: '#0a0a0a', border: '1px solid #00aa00',
                borderRadius: '15px', padding: '35px',
                cursor: 'pointer'
              }}
            >
              <div style={{fontSize: '50px', marginBottom: '15px'}}>{service.icon}</div>
              <h3 style={{color: '#ffd700', fontSize: '22px', marginBottom: '12px'}}>{service.titre}</h3>
              <p style={{color: '#cccccc', fontSize: '14px', lineHeight: '1.7', marginBottom: '20px'}}>{service.description}</p>
              <ul style={{listStyle: 'none', padding: 0}}>
                {service.details.map((detail, i) => (
                  <li key={i} style={{color: '#00aa00', fontSize: '13px', marginBottom: '6px'}}>
                    ✓ {detail}
                  </li>
                ))}
              </ul>
            </motion.div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <motion.section
        initial={{opacity: 0}}
        whileInView={{opacity: 1}}
        transition={{duration: 0.8}}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: '#0a0a0a', borderTop: '2px solid #00aa00'
        }}
      >
        <h2 style={{color: '#ffd700', fontSize: '32px', marginBottom: '15px'}}>
          Intéressé par mes services ?
        </h2>
        <p style={{color: '#aaaaaa', marginBottom: '30px', fontSize: '16px'}}>
          Contactez-moi pour discuter de votre projet
        </p>
        <Link to="/contact" style={{
          background: '#00aa00', color: '#ffffff',
          padding: '15px 40px', borderRadius: '30px',
          textDecoration: 'none', fontSize: '16px', fontWeight: 'bold'
        }}>
          Demander un devis gratuit
        </Link>
      </motion.section>
    </div>
  );
}

export default Services;
